<?php
session_start(); require 'config/db.php'; require 'includes/functions.php'; ensure_portal_schema($pdo); if(empty($_SESSION['client'])) redirect('client_login.php');
$client=$_SESSION['client']; try{ $pdo->query("CREATE TABLE IF NOT EXISTS ClientWishlist (id INT AUTO_INCREMENT PRIMARY KEY, klient_id INT, produkt_id INT, data_krijimit DATETIME DEFAULT CURRENT_TIMESTAMP, UNIQUE KEY uniq_wish(klient_id,produkt_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4"); }catch(Exception $e){}
if(isset($_GET['remove'])){ $st=$pdo->prepare('DELETE FROM ClientWishlist WHERE id=? AND klient_id=?'); $st->execute([(int)$_GET['remove'],(int)$client['klient_id']]); redirect('client_wishlist.php'); }
$st=$pdo->prepare('SELECT w.id,p.* FROM ClientWishlist w JOIN Produktet p ON p.produkt_id=w.produkt_id WHERE w.klient_id=? ORDER BY w.id DESC'); $st->execute([(int)$client['klient_id']]); $items=$st->fetchAll();
$portalRole='client'; $portalUser=$client; $pageTitle='Wishlist'; include 'includes/portal_header.php'; ?>
<section class="page-title-card"><div><span class="eyebrow">💎 Wishlist</span><h1>Produktet që dëshiron</h1><p class="muted">Produktet që ke ruajtur për t’i blerë më vonë.</p></div><a class="btn primary" href="client_shop.php">Katalogu</a></section>
<div class="wishlist-grid modern-mini-products"><?php foreach($items as $p): ?><div class="mini-product-card wishlist-card"><a class="remove-x" href="client_wishlist.php?remove=<?=$p['id']?>">×</a><span class="mini-icon">💎</span><b><?=e($p['emri'])?></b><p><?=e($p['barkodi'])?></p><div class="shop-price"><?=money($p['cmimi'])?></div><span class="badge ok">Në stok: <?=e($p['sasia_ne_stok'])?></span><div class="product-actions"><a class="btn primary small" href="client_shop.php?q=<?=urlencode($p['emri'])?>">🛍️ Bli</a><a class="btn secondary small" href="client_cart.php">🛒 Shporta</a></div></div><?php endforeach; if(!$items): ?><div class="card"><p class="muted">Wishlist është bosh.</p></div><?php endif; ?></div><?php include 'includes/portal_footer.php'; ?>
